let shardID = event.item._id;
let shard = actor.items.filter(y => y._id == shardID)[0];
let enhanceEff = event.item.transferredEffects.filter(x => x.name == "Shardplate Enhance")[0];
let reactEff = event.item.transferredEffects.filter(x => x.name == "Shardplate Reaction")[0];
if (shard.system.activation.uses.value == 0) {
	await enhanceEff.update({disabled:true});
	if (reactEff.disabled) {
		await shard.update({
			'system.deflects.spirit.active': false,
			'system.deflects.vital.active': false
		});
	}
	await shard.update({'system.traits.cumbersome': {"defaultActive": true, "defaultValue": 6, "expertise": {"toggleActive": false, "value": null}, "value": 6, "active": true}
	});
} else {
	if (shard.system.equipped) {
		await enhanceEff.update({disabled:false});
	}
	await shard.update({
		'system.deflects.spirit.active': true,
		'system.deflects.vital.active': true,
		'system.traits.cumbersome': {"defaultActive": false, "defaultValue": 0, "expertise": {"toggleActive": false, "value": null}, "value": 0, "active": false}
	});
}

let enhanceEff = event.item.transferredEffects.filter(x => x.name == "Shardplate Enhance")[0];
if (event.item.system.activation.uses.value > 0) {
await enhanceEff.update({disabled:false});
}

let reactEff = event.item.transferredEffects.filter(x => x.name == "Shardplate Reaction")[0];
  await reactEff.update({disabled:true});
if (event.item.system.activation.uses.value == 0) {
	let shardID = event.item._id;
	let shard = actor.items.filter(y => y._id == shardID)[0];
	await shard.update({
		'system.deflects.spirit.active': false,
		'system.deflects.vital.active': false
	});
}

let reactEff = event.item.transferredEffects.filter(x => x.name == "Shardplate Reaction")[0];
if (reactEff.disabled) {
  await reactEff.update({disabled:false});
} else if (!reactEff.disabled) {
  await reactEff.update({disabled:true});
  let shard = actor.items.filter(y => y._id == event.item._id)[0];
